#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    pid_t pid;
    int count = 5;

    printf("Parent: Starting process creation\n");

    pid = fork();  // Create new process

    if (pid < 0) {
        // Error occurred
        printf("Fork failed!\n");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child: I am the child process\n");
        printf("Child: My PID = %d\n", getpid());
        printf("Child: Parent's PID = %d\n", getppid());
        printf("Child: count = %d\n", count);
        count = 10;
        printf("Child: count changed to %d\n", count);
        printf("Child: Exiting\n");
    }
    else {
        // Parent process
        printf("Parent: Child created with PID = %d\n", pid);
        printf("Parent: Waiting for child...\n");
        wait(NULL);  // Wait for child to finish
        printf("Parent: Child finished execution\n");
        printf("Parent: count = %d (unchanged)\n", count);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Process {
    int pid;
    int arrival_time;
    int burst_time;
    int remaining_time;
    int waiting_time;
    int turnaround_time;
};

void round_robin(struct Process processes[], int n, int time_quantum) {
    int current_time = 0;
    int completed = 0;

    printf("\n=== Round Robin Scheduling ===\n");
    printf("Time Quantum: %d\n\n", time_quantum);

    while (completed < n) {
        for (int i = 0; i < n; i++) {
            // Skip if process already completed
            if (processes[i].remaining_time <= 0) continue;

            // Skip if process hasn't arrived yet
            if (processes[i].arrival_time > current_time) continue;

            printf("Time %d: Process %d is executing\n", 
                   current_time, processes[i].pid);

            // Execute for time quantum or remaining time
            int execute_time = (processes[i].remaining_time > time_quantum) 
                               ? time_quantum 
                               : processes[i].remaining_time;

            processes[i].remaining_time -= execute_time;
            current_time += execute_time;

            // Calculate waiting time
            if (processes[i].remaining_time > 0) {
                // Process was preempted
            } else {
                // Process completed
                processes[i].turnaround_time = current_time - processes[i].arrival_time;
                processes[i].waiting_time = processes[i].turnaround_time - processes[i].burst_time;
                completed++;
                printf("Time %d: Process %d completed\n", current_time, processes[i].pid);
            }
        }
    }

    // Print results
    float avg_waiting = 0, avg_turnaround = 0;
    printf("\n=== Results ===\n");
    printf("PID\tArrival\tBurst\tWait\tTurnaround\n");

    for (int i = 0; i < n; i++) {
        printf("%d\t%d\t\t%d\t%d\t%d\n", 
               processes[i].pid, processes[i].arrival_time,
               processes[i].burst_time, processes[i].waiting_time,
               processes[i].turnaround_time);
        avg_waiting += processes[i].waiting_time;
        avg_turnaround += processes[i].turnaround_time;
    }

    printf("\nAverage Waiting Time: %.2f", avg_waiting/n);
    printf("\nAverage Turnaround Time: %.2f\n", avg_turnaround/n);
}

int main() {
    int n = 4;
    int time_quantum = 4;

    struct Process processes[] = {
        {1, 0, 10, 10, 0, 0},
        {2, 1, 5, 5, 0, 0},
        {3, 2, 8, 8, 0, 0},
        {4, 3, 6, 6, 0, 0}
    };

    round_robin(processes, n, time_quantum);

    return 0;
}
